-- ══════════════════════════════════════════════════════════════════
-- Phase 8A — ORC conversation metadata column
-- ══════════════════════════════════════════════════════════════════
-- Adds a `metadata` jsonb column to agent_conversations. Holds the
-- per-conversation state that ORC's reply path needs to run the
-- context economy cheaply:
--
--   {
--     "summary": string,
--       -- Compressed prose of messages before `summary_through_index`.
--       -- Regenerated by a cheap Flash summarization call when the
--       -- verbatim window exceeds its cap (see ORC.md Phase 8 rules).
--     "summary_through_index": number,
--       -- Messages 0..N-1 are in the summary; messages N.. are verbatim.
--       -- Advanced by 6 each time summarization runs.
--     "summary_updated_at": timestamp (ISO string),
--
--     "gemini_cache_name": string | null,
--       -- Name of the Gemini caches.create() resource holding the
--       -- stable prefix (system prompt + brand DNA + signal core).
--       -- Reused across turns within its TTL (Gemini default is 1h).
--     "gemini_cache_expires_at": timestamp (ISO string) | null
--       -- When gemini_cache_name should be considered stale and
--       -- re-created. Anthropic caches are automatic (5-min TTL
--       -- extended on re-hit), OpenAI is implicit — only Gemini
--       -- needs explicit lifecycle management.
--   }
--
-- Default `{}::jsonb` so existing rows (4 ORC conversations from
-- Phase 7) don't need a data backfill; metadata gets populated
-- lazily on the first ORC turn after Phase 8 ships.
-- ══════════════════════════════════════════════════════════════════

ALTER TABLE "agent_conversations"
  ADD COLUMN "metadata" JSONB NOT NULL DEFAULT '{}'::jsonb;
